141	/// Returns `(mean, population_stddev)`.
142	/// Returns `None` when there are fewer than 2 samples or all values are identical.
143	fn compute_stats(values: &[f64]) -> Option<(f64, f64)> {
144	    let n = values.len();
145	    if n < 2 {
146	        return None;
147	    }
148	    let mean = values.iter().sum::<f64>() / n as f64;
149	    let variance = values.iter().map(|v| (v - mean).powi(2)).sum::<f64>() / n as f64;
150	    let stddev = variance.sqrt();
151	    if stddev < f64::EPSILON {
152	        return None; // all identical — no outliers possible
153	    }
154	    Some((mean, stddev))
155	}
