267	pub async fn create_asset(
268	    conn: &DatabaseConnection,
269	    cipher: &Cipher,
270	    user_id: i64,
271	    req: CreateAssetRequest,
272	) -> AppResult<AssetResponse> {
273	    validate_create_fields(&req)?;
274	    let category = parse_category(&req.category)?;
275	    let status = parse_status(req.status.as_deref().unwrap_or("in_service"))?;
276	    let cost = req
277	        .procurement_cost
278	        .map(|c| Decimal::from_str(&c.to_string()))
279	        .transpose()
280	        .map_err(|_| AppError::BadRequest("Invalid procurement_cost".into()))?;
281	
282	    // Encrypt serial_number before storing.
283	    let serial_encrypted = cipher
284	        .encrypt_opt(req.serial_number.as_deref())
285	        .map_err(enc_err)?;
286	
287	    let now = Utc::now();
288	
289	    let model = conn
290	        .transaction::<_, asset_entity::Model, AppError>(|txn| {
291	            let req = req.clone();
292	            let category = category.clone();
293	            let status = status.clone();
294	            let serial_encrypted = serial_encrypted.clone();
295	            Box::pin(async move {
296	                let inserted = AssetActiveModel {
297	                    asset_code: Set(req.asset_code.trim().to_owned()),
298	                    category: Set(category),
299	                    brand: Set(req.brand.trim().to_owned()),
300	                    model: Set(req.model.trim().to_owned()),
301	                    serial_number: Set(serial_encrypted),
302	                    status: Set(status),
303	                    owner_id: Set(req.owner_id),
304	                    responsible_person_id: Set(req.responsible_person_id),
305	                    procurement_cost: Set(cost),
306	                    procurement_date: Set(req.procurement_date.clone()),
307	                    useful_life_months: Set(req.useful_life_months),
308	                    notes: Set(req.notes.clone()),
309	                    created_at: Set(now),
310	                    updated_at: Set(now),
311	                    ..Default::default()
312	                }
313	                .insert(txn)
314	                .await
315	                .map_err(|e| {
316	                    let msg = e.to_string();
317	                    if msg.contains("UNIQUE") {
318	                        AppError::Conflict(format!(
319	                            "Asset code '{}' already exists",
320	                            req.asset_code
321	                        ))
322	                    } else {
323	                        AppError::Internal(msg)
324	                    }
325	                })?;
326	
327	                let snap = snapshot_json(&inserted);
328	                record_audit(txn, inserted.id, user_id, "created", &snap)
329	                    .await
330	                    .map_err(|e| AppError::Internal(e.to_string()))?;
331	
332	                Ok(inserted)
333	            })
334	        })
335	        .await
336	        .map_err(tx_err)?;
337	
338	    tracing::info!(
339	        asset_id = model.id,
340	        asset_code = %model.asset_code,
341	        user_id,
342	        "assets.created"
343	    );
344	    to_response(cipher, &model)
345	}
