10	// ── Constants ─────────────────────────────────────────────────────────────────
11	
12	/// Filename prefix for all backup files.
13	const BACKUP_PREFIX: &str = "backup_";
14	/// Extension used for SQLite backup files.
15	const BACKUP_EXT: &str = "sqlite";
16	/// Sentinel file written by the restore endpoint; read by the next startup.
17	const RESTORE_MARKER: &str = ".restore_pending";
18	
19	// ── Helpers ───────────────────────────────────────────────────────────────────
