304	/// Extract the filesystem path from a SQLite `DATABASE_URL`.
305	///
306	/// Handles the common formats used by sqlx/sea-orm:
307	/// - `sqlite:///absolute/path.db`  →  `/absolute/path.db`
308	/// - `sqlite://./relative.db`       →  `./relative.db`
309	/// - `sqlite://relative.db`         →  `relative.db`
310	pub fn db_path_from_url(url: &str) -> Option<PathBuf> {
311	    let stripped = url.strip_prefix("sqlite://")?;
312	    // Triple-slash absolute path: strip one leading slash.
313	    let path_str = if let Some(s) = stripped.strip_prefix('/') {
314	        format!("/{s}")
315	    } else {
316	        stripped.to_owned()
317	    };
318	    Some(PathBuf::from(path_str))
319	}
