90	// ── Depreciation ──────────────────────────────────────────────────────────────
91	
92	fn compute_depreciation(
93	    procurement_cost: Option<Decimal>,
94	    procurement_date: Option<&str>,
95	    useful_life_months: Option<i32>,
96	) -> (Option<f64>, Option<f64>, bool) {
97	    let (Some(cost), Some(date_str), Some(life)) =
98	        (procurement_cost, procurement_date, useful_life_months)
99	    else {
100	        return (None, None, false);
101	    };
102	
103	    if life <= 0 {
104	        return (None, None, false);
105	    }
106	
107	    let cost_f = match cost.to_string().parse::<f64>() {
108	        Ok(v) => v,
109	        Err(_) => return (None, None, false),
110	    };
111	
112	    let monthly = cost_f / life as f64;
113	
114	    let Ok(start_date) = NaiveDate::parse_from_str(date_str, "%Y-%m-%d") else {
115	        return (None, None, false);
116	    };
117	
118	    let today = Utc::now().date_naive();
119	    let months_elapsed = (today.year() - start_date.year()) * 12
120	        + (today.month() as i32 - start_date.month() as i32);
121	    let months_elapsed = months_elapsed.max(0) as i32;
122	
123	    let accumulated = (monthly * months_elapsed as f64).min(cost_f);
124	    let book_value = (cost_f - accumulated).max(0.0);
125	    let fully_depreciated = months_elapsed >= life;
126	
127	    (Some(monthly), Some(book_value), fully_depreciated)
128	}
