11	
12	// ── Error variants ────────────────────────────────────────────────────────────
13	
14	#[derive(Error, Debug)]
15	pub enum AppError {
16	    #[error("Resource not found: {0}")]
17	    NotFound(String),
18	
19	    #[error("Bad request: {0}")]
20	    BadRequest(String),
21	
22	    #[error("Unprocessable entity: {0}")]
23	    UnprocessableEntity(String),
24	
25	    #[error("Conflict: {0}")]
26	    Conflict(String),
27	
28	    #[error("Unauthorized: {0}")]
29	    Unauthorized(String),
30	
31	    #[error("Forbidden: {0}")]
32	    Forbidden(String),
33	
34	    #[error("Internal server error: {0}")]
35	    Internal(String),
36	
37	    #[error("Configuration error: {0}")]
38	    Config(String),
39	}
40	
41	pub type AppResult<T> = Result<T, AppError>;
42	
43	// ── Wire format ───────────────────────────────────────────────────────────────
44	
45	/// JSON body returned on every error response.
46	#[derive(Serialize)]
47	pub struct ErrorBody {
48	    /// Machine-readable error code.
49	    pub code: &'static str,
50	    /// Human-readable description.
51	    pub message: String,
52	    /// Echoes the request correlation ID to simplify log correlation.
53	    #[serde(skip_serializing_if = "Option::is_none")]
54	    pub correlation_id: Option<String>,
55	}
56	
57	// ── Rocket Responder ──────────────────────────────────────────────────────────
58	
59	impl<'r> Responder<'r, 'static> for AppError {
60	    fn respond_to(self, req: &'r Request<'_>) -> response::Result<'static> {
61	        let (status, code) = match &self {
62	            AppError::NotFound(_) => (Status::NotFound, "NOT_FOUND"),
63	            AppError::BadRequest(_) => (Status::BadRequest, "BAD_REQUEST"),
64	            AppError::UnprocessableEntity(_) => {
65	                (Status::UnprocessableEntity, "UNPROCESSABLE_ENTITY")
66	            }
67	            AppError::Conflict(_) => (Status::Conflict, "CONFLICT"),
68	            AppError::Unauthorized(_) => (Status::Unauthorized, "UNAUTHORIZED"),
69	            AppError::Forbidden(_) => (Status::Forbidden, "FORBIDDEN"),
70	            AppError::Internal(_) | AppError::Config(_) => {
71	                (Status::InternalServerError, "INTERNAL_ERROR")
72	            }
73	        };
74	
75	        // Pull the correlation ID that was stamped by CorrelationFairing.
76	        let cid = req.local_cache(|| CorrelationId(String::new())).0.clone();
77	
78	        // Internal/Config variants must never leak implementation details to clients.
79	        let message = match &self {
80	            AppError::Internal(detail) | AppError::Config(detail) => {
81	                tracing::error!(error = %detail, correlation_id = %cid, "internal_error");
82	                "An internal error occurred. Please reference the correlation ID when contacting support.".to_string()
83	            }
84	            other => other.to_string(),
85	        };
86	
87	        let body = ErrorBody {
88	            code,
89	            message,
90	            correlation_id: if cid.is_empty() { None } else { Some(cid) },
91	        };
92	
93	        let mut response = Json(body).respond_to(req)?;
94	        response.set_status(status);
95	        Ok(response)
96	    }
97	}
