1	use rocket::{
2	    fairing::{Fairing, Info, Kind},
3	    http::Header,
4	    Data, Request, Response,
5	};
6	use uuid::Uuid;
7	
8	/// Request-local store for the correlation ID.
9	///
10	/// Stored via `Request::local_cache` so both fairings and route handlers can
11	/// read it without passing it explicitly through every function call.
12	pub struct CorrelationId(pub String);
13	
14	/// Fairing that stamps every request with a correlation ID.
15	///
16	/// Behaviour:
17	/// - If the caller already supplies `X-Correlation-ID`, that value is reused
18	///   (useful for end-to-end tracing across services).
19	/// - Otherwise a new UUIDv4 is generated.
20	/// - The final ID is echoed back in the `X-Correlation-ID` response header.
21	pub struct CorrelationFairing;
22	
23	#[rocket::async_trait]
24	impl Fairing for CorrelationFairing {
25	    fn info(&self) -> Info {
26	        Info {
27	            name: "Correlation ID",
28	            kind: Kind::Request | Kind::Response,
29	        }
30	    }
31	
32	    async fn on_request(&self, req: &mut Request<'_>, _data: &mut Data<'_>) {
33	        let id = req
34	            .headers()
35	            .get_one("X-Correlation-ID")
36	            .filter(|v| !v.is_empty())
37	            .map(str::to_owned)
38	            .unwrap_or_else(|| Uuid::new_v4().to_string());
39	
40	        req.local_cache(|| CorrelationId(id));
41	    }
42	
43	    async fn on_response<'r>(&self, req: &'r Request<'_>, res: &mut Response<'r>) {
44	        let id = req.local_cache(|| CorrelationId(String::new())).0.clone();
45	        if !id.is_empty() {
46	            res.set_header(Header::new("X-Correlation-ID", id));
47	        }
48	    }
49	}
