152	/// Compute the `line_total` for a new line request.
153	///
154	/// Formula:
155	/// ```text
156	/// base  = quantity × unit_price
157	/// adj   = percentage ? base × (value/100) : value
158	/// total = base − adj (discount)  |  base + adj (surcharge)
159	/// total = max(0, total)
160	/// ```
161	fn compute_line_total(
162	    quantity: Decimal,
163	    unit_price: Decimal,
164	    adj_type: Option<&AdjustmentType>,
165	    adj_is_pct: bool,
166	    adj_value: Option<Decimal>,
167	) -> AppResult<Decimal> {
168	    let base = (quantity * unit_price).round_dp(MONEY_DP);
169	
170	    let Some(adj_type) = adj_type else {
171	        return Ok(base);
172	    };
173	    let adj_value = adj_value.unwrap_or(Decimal::ZERO);
174	
175	    let adj_amount = if adj_is_pct {
176	        (base * (adj_value / Decimal::ONE_HUNDRED)).round_dp(MONEY_DP)
177	    } else {
178	        adj_value.round_dp(MONEY_DP)
179	    };
180	
181	    let total = match adj_type {
182	        AdjustmentType::Discount => base - adj_amount,
183	        AdjustmentType::Surcharge => base + adj_amount,
184	    };
185	
186	    Ok(total.max(Decimal::ZERO))
187	}
