189	/// Recompute `subtotal`, `tax`, `discount_amount`, and `total` for an invoice
190	/// from its current line items and stored discount settings.
191	///
192	/// All amounts are rounded to 4 decimal places.
193	async fn recompute_invoice_totals(
194	    txn: &impl sea_orm::ConnectionTrait,
195	    invoice_id: i64,
196	    tax_rate: Decimal,
197	    discount_type: Option<&str>,
198	    discount_value: Option<Decimal>,
199	) -> Result<(Decimal, Decimal, Decimal, Decimal), sea_orm::DbErr> {
200	    let lines = line_entity::Entity::find()
201	        .filter(line_entity::Column::InvoiceId.eq(invoice_id))
202	        .all(txn)
203	        .await?;
204	
205	    let subtotal = lines
206	        .iter()
207	        .fold(Decimal::ZERO, |acc, l| acc + l.line_total)
208	        .round_dp(MONEY_DP);
209	
210	    let tax = (subtotal * tax_rate).round_dp(MONEY_DP);
211	
212	    // Invoice-level discount.
213	    let discount_amount = match (discount_type, discount_value) {
214	        (Some("percentage"), Some(pct)) => {
215	            let raw = (subtotal * (pct / Decimal::ONE_HUNDRED)).round_dp(MONEY_DP);
216	            raw.min(MAX_DISCOUNT_AMOUNT)
217	        }
218	        (Some("fixed_amount"), Some(amt)) => amt.round_dp(MONEY_DP).min(MAX_DISCOUNT_AMOUNT),
219	        _ => Decimal::ZERO,
220	    };
221	
222	    let total = (subtotal + tax - discount_amount).max(Decimal::ZERO);
223	
224	    Ok((subtotal, tax, discount_amount, total))
225	}
