75	// ── Public service functions ──────────────────────────────────────────────────
76	
77	/// Create an immediate backup of the live database using SQLite's `VACUUM INTO`
78	/// command, then rotate old backups so at most `retain_days` copies are kept.
79	///
80	/// `VACUUM INTO` produces a compact, defragmented copy that is safe to take
81	/// against a live database in WAL mode.
82	pub async fn create_backup(
83	    conn: &DatabaseConnection,
84	    backup_dir: &Path,
85	    retain_days: u32,
86	) -> AppResult<BackupEntry> {
87	    ensure_backup_dir(backup_dir)?;
88	
89	    let filename = backup_filename();
90	    let backup_path = backup_dir.join(&filename);
91	
92	    let path_str = backup_path
93	        .to_str()
94	        .ok_or_else(|| AppError::Internal("Backup path contains non-UTF-8 characters".into()))?;
95	
96	    // Reject paths that would break the SQL literal.  In practice, backup_dir
97	    // comes from AppConfig (not user input) and backup_filename() is alphanumeric
98	    // only, so this guard is a belt-and-suspenders safety net.
99	    if path_str.contains('\'') {
100	        return Err(AppError::Internal(
101	            "Backup path must not contain single-quote characters".into(),
102	        ));
103	    }
104	
105	    // VACUUM INTO does not support parameterised values; the path is embedded
106	    // as a SQL string literal.
107	    let sql = format!("VACUUM INTO '{path_str}'");
108	    conn.execute(Statement::from_string(DbBackend::Sqlite, sql))
109	        .await
110	        .map_err(|e| AppError::Internal(format!("VACUUM INTO failed: {e}")))?;
111	
112	    tracing::info!(
113	        filename = %filename,
114	        path     = %backup_path.display(),
115	        "backup.created"
116	    );
117	
118	    rotate_backups(backup_dir, retain_days)?;
119	
120	    entry_from_path(&backup_path)
121	        .ok_or_else(|| AppError::Internal("Failed to read backup metadata after creation".into()))
122	}
123	
124	/// Delete all but the `retain_days` most recent backup files.
125	///
126	/// Files are sorted lexicographically by filename (which equals chronological
127	/// order given the `YYYYMMDD_HHMMSS` timestamp prefix).
128	pub fn rotate_backups(backup_dir: &Path, retain_days: u32) -> AppResult<()> {
129	    let mut backups = list_backup_files(backup_dir)?;
130	    backups.sort_by(|a, b| a.filename.cmp(&b.filename));
131	
132	    let to_delete = backups.len().saturating_sub(retain_days as usize);
133	
134	    for entry in backups.iter().take(to_delete) {
135	        let path = backup_dir.join(&entry.filename);
136	        if let Err(e) = std::fs::remove_file(&path) {
137	            tracing::warn!(
138	                path = %path.display(),
139	                error = %e,
140	                "backup.rotation_delete_failed"
141	            );
142	        } else {
143	            tracing::info!(filename = %entry.filename, "backup.rotated_out");
144	        }
145	    }
146	
147	    Ok(())
148	}
