252	// ── Startup restore logic ─────────────────────────────────────────────────────
253	
254	/// Called at application startup (before any connections are opened) to check
255	/// whether a restore was staged by the previous run.
256	///
257	/// If the marker file exists the backup is copied over the target database
258	/// file.  On success the marker is deleted and a log line is emitted.
259	///
260	/// # Arguments
261	/// * `backup_dir` — the configured backup directory
262	/// * `db_file_path` — filesystem path of the primary SQLite database file
263	pub fn apply_pending_restore(backup_dir: &Path, db_file_path: &Path) -> Result<bool, String> {
264	    let marker = backup_dir.join(RESTORE_MARKER);
265	    if !marker.exists() {
266	        return Ok(false);
267	    }
268	
269	    let content =
270	        std::fs::read_to_string(&marker).map_err(|e| format!("Cannot read restore marker: {e}"))?;
271	    let backup_path = PathBuf::from(content.trim());
272	
273	    if !backup_path.exists() {
274	        std::fs::remove_file(&marker).ok();
275	        return Err(format!(
276	            "Staged restore file '{}' no longer exists — marker removed",
277	            backup_path.display()
278	        ));
279	    }
280	
281	    // Validate before overwriting.
282	    validate_sqlite_file(&backup_path)
283	        .map_err(|e| format!("Staged restore file is corrupt: {e}"))?;
284	
285	    // Ensure the target directory exists.
286	    if let Some(parent) = db_file_path.parent() {
287	        std::fs::create_dir_all(parent).map_err(|e| format!("Cannot create db directory: {e}"))?;
288	    }
289	
290	    std::fs::copy(&backup_path, db_file_path).map_err(|e| format!("Restore copy failed: {e}"))?;
291	
292	    std::fs::remove_file(&marker)
293	        .map_err(|e| format!("Cannot remove restore marker after apply: {e}"))?;
294	
295	    tracing::info!(
296	        backup = %backup_path.display(),
297	        target = %db_file_path.display(),
298	        "backup.restore_applied"
299	    );
300	
301	    Ok(true)
302	}
