17	const RESTORE_MARKER: &str = ".restore_pending";
18	
19	// ── Helpers ───────────────────────────────────────────────────────────────────
20	
21	/// Generate a timestamped backup filename, e.g. `backup_20260407_230000.sqlite`.
22	fn backup_filename() -> String {
23	    let ts = Utc::now().format("%Y%m%d_%H%M%S");
24	    format!("{BACKUP_PREFIX}{ts}.{BACKUP_EXT}")
25	}
26	
27	/// Parse a `BackupEntry` from a filesystem path.  Returns `None` if the file
28	/// does not match the expected naming scheme.
29	fn entry_from_path(path: &Path) -> Option<BackupEntry> {
30	    let filename = path.file_name()?.to_str()?.to_owned();
31	    if !filename.starts_with(BACKUP_PREFIX) || !filename.ends_with(BACKUP_EXT) {
32	        return None;
33	    }
34	
35	    let size_bytes = path.metadata().ok()?.len();
36	
37	    // Extract the timestamp portion: `backup_YYYYMMDD_HHMMSS.sqlite`
38	    let ts_part = filename
39	        .strip_prefix(BACKUP_PREFIX)?
40	        .strip_suffix(&format!(".{BACKUP_EXT}"))?;
41	
42	    // Convert compact timestamp to readable ISO 8601.
43	    // Format: YYYYMMDD_HHMMSS → YYYY-MM-DDTHH:MM:SSZ
44	    let created_at = if ts_part.len() == 15 {
45	        format!(
46	            "{}-{}-{}T{}:{}:{}Z",
47	            &ts_part[0..4],
48	            &ts_part[4..6],
49	            &ts_part[6..8],
50	            &ts_part[9..11],
51	            &ts_part[11..13],
52	            &ts_part[13..15],
53	        )
54	    } else {
55	        ts_part.to_owned()
56	    };
57	
58	    Some(BackupEntry {
59	        filename,
60	        size_bytes,
61	        created_at,
62	    })
63	}
64	
65	/// Ensure the backup directory exists, creating it if necessary.
66	fn ensure_backup_dir(backup_dir: &Path) -> AppResult<()> {
67	    std::fs::create_dir_all(backup_dir).map_err(|e| {
68	        AppError::Internal(format!(
69	            "Cannot create backup directory '{}': {e}",
70	            backup_dir.display()
71	        ))
72	    })
73	}
74	
75	// ── Public service functions ──────────────────────────────────────────────────
76	
77	/// Create an immediate backup of the live database using SQLite's `VACUUM INTO`
78	/// command, then rotate old backups so at most `retain_days` copies are kept.
79	///
80	/// `VACUUM INTO` produces a compact, defragmented copy that is safe to take
81	/// against a live database in WAL mode.
82	pub async fn create_backup(
83	    conn: &DatabaseConnection,
84	    backup_dir: &Path,
85	    retain_days: u32,
86	) -> AppResult<BackupEntry> {
87	    ensure_backup_dir(backup_dir)?;
88	
89	    let filename = backup_filename();
90	    let backup_path = backup_dir.join(&filename);
91	
92	    let path_str = backup_path
93	        .to_str()
94	        .ok_or_else(|| AppError::Internal("Backup path contains non-UTF-8 characters".into()))?;
95	
96	    // Reject paths that would break the SQL literal.  In practice, backup_dir
97	    // comes from AppConfig (not user input) and backup_filename() is alphanumeric
98	    // only, so this guard is a belt-and-suspenders safety net.
99	    if path_str.contains('\'') {
100	        return Err(AppError::Internal(
101	            "Backup path must not contain single-quote characters".into(),
102	        ));
103	    }
104	
105	    // VACUUM INTO does not support parameterised values; the path is embedded
106	    // as a SQL string literal.
107	    let sql = format!("VACUUM INTO '{path_str}'");
108	    conn.execute(Statement::from_string(DbBackend::Sqlite, sql))
109	        .await
110	        .map_err(|e| AppError::Internal(format!("VACUUM INTO failed: {e}")))?;
111	
112	    tracing::info!(
113	        filename = %filename,
114	        path     = %backup_path.display(),
115	        "backup.created"
116	    );
117	
118	    rotate_backups(backup_dir, retain_days)?;
119	
120	    entry_from_path(&backup_path)
121	        .ok_or_else(|| AppError::Internal("Failed to read backup metadata after creation".into()))
122	}
123	
124	/// Delete all but the `retain_days` most recent backup files.
125	///
126	/// Files are sorted lexicographically by filename (which equals chronological
127	/// order given the `YYYYMMDD_HHMMSS` timestamp prefix).
128	pub fn rotate_backups(backup_dir: &Path, retain_days: u32) -> AppResult<()> {
129	    let mut backups = list_backup_files(backup_dir)?;
130	    backups.sort_by(|a, b| a.filename.cmp(&b.filename));
131	
132	    let to_delete = backups.len().saturating_sub(retain_days as usize);
133	
134	    for entry in backups.iter().take(to_delete) {
135	        let path = backup_dir.join(&entry.filename);
136	        if let Err(e) = std::fs::remove_file(&path) {
137	            tracing::warn!(
138	                path = %path.display(),
139	                error = %e,
140	                "backup.rotation_delete_failed"
141	            );
142	        } else {
143	            tracing::info!(filename = %entry.filename, "backup.rotated_out");
144	        }
145	    }
146	
147	    Ok(())
148	}
149	
150	/// List all backup files present in the backup directory, newest first.
151	pub fn list_backup_files(backup_dir: &Path) -> AppResult<Vec<BackupEntry>> {
152	    if !backup_dir.exists() {
153	        return Ok(vec![]);
154	    }
155	
156	    let mut entries = std::fs::read_dir(backup_dir)
157	        .map_err(|e| {
158	            AppError::Internal(format!(
159	                "Cannot read backup directory '{}': {e}",
160	                backup_dir.display()
161	            ))
162	        })?
163	        .filter_map(|res| {
164	            let entry = res.ok()?;
165	            entry_from_path(&entry.path())
166	        })
167	        .collect::<Vec<_>>();
168	
169	    // Newest first.
170	    entries.sort_by(|a, b| b.filename.cmp(&a.filename));
171	    Ok(entries)
172	}
173	
174	/// Return a structured listing response for the admin endpoint.
175	pub fn list_backups(backup_dir: &Path, retain_days: u32) -> AppResult<BackupListResponse> {
176	    let backups = list_backup_files(backup_dir)?;
177	    Ok(BackupListResponse {
178	        backups,
179	        backup_dir: backup_dir.display().to_string(),
180	        retain_days,
181	    })
182	}
183	
184	/// Stage a restore from `filename` inside `backup_dir`.
185	///
186	/// This writes a sentinel file (`{backup_dir}/.restore_pending`) whose content
187	/// is the absolute path of the chosen backup file.  On the **next server
188	/// startup**, `db::apply_pending_restore` reads this marker, copies the backup
189	/// over the live database file, and deletes the marker before opening any
190	/// connections.
191	///
192	/// The running process continues to serve requests normally after this call;
193	/// the restore takes effect only after a restart.
194	pub fn stage_restore(backup_dir: &Path, filename: &str) -> AppResult<PathBuf> {
195	    // Safety: reject any path traversal attempts.
196	    if filename.contains('/') || filename.contains('\\') || filename.contains("..") {
197	        return Err(AppError::BadRequest(
198	            "filename must not contain path separators or '..'".into(),
199	        ));
200	    }
201	    if !filename.starts_with(BACKUP_PREFIX) || !filename.ends_with(BACKUP_EXT) {
202	        return Err(AppError::BadRequest(format!(
203	            "filename must match backup_YYYYMMDD_HHMMSS.{BACKUP_EXT}"
204	        )));
205	    }
206	
207	    let backup_path = backup_dir.join(filename);
208	    if !backup_path.exists() {
209	        return Err(AppError::NotFound(format!("Backup '{filename}' not found")));
210	    }
211	
212	    // Verify the file is a valid SQLite database (magic bytes check).
213	    validate_sqlite_file(&backup_path)?;
214	
215	    // Write absolute path into the marker file.
216	    let abs_path = backup_path
217	        .canonicalize()
218	        .map_err(|e| AppError::Internal(format!("Cannot resolve backup path: {e}")))?;
219	    let marker = backup_dir.join(RESTORE_MARKER);
220	    std::fs::write(&marker, abs_path.to_str().unwrap_or(""))
221	        .map_err(|e| AppError::Internal(format!("Failed to write restore marker: {e}")))?;
222	
223	    tracing::info!(
224	        filename = %filename,
225	        marker   = %marker.display(),
226	        "backup.restore_staged"
227	    );
228	
229	    Ok(abs_path)
230	}
231	
232	/// Check the SQLite file signature (first 16 bytes must be the SQLite magic string).
233	fn validate_sqlite_file(path: &Path) -> AppResult<()> {
234	    use std::io::Read;
235	
236	    let mut f = std::fs::File::open(path)
237	        .map_err(|e| AppError::Internal(format!("Cannot open backup file: {e}")))?;
238	
239	    let mut magic = [0u8; 16];
240	    f.read_exact(&mut magic)
241	        .map_err(|e| AppError::Internal(format!("Cannot read backup file header: {e}")))?;
242	
243	    if &magic != b"SQLite format 3\0" {
244	        return Err(AppError::BadRequest(format!(
245	            "'{}' is not a valid SQLite database",
246	            path.file_name().unwrap_or_default().to_string_lossy()
247	        )));
248	    }
249	    Ok(())
250	}
251	
252	// ── Startup restore logic ─────────────────────────────────────────────────────
253	
254	/// Called at application startup (before any connections are opened) to check
255	/// whether a restore was staged by the previous run.
256	///
257	/// If the marker file exists the backup is copied over the target database
258	/// file.  On success the marker is deleted and a log line is emitted.
259	///
260	/// # Arguments
261	/// * `backup_dir` — the configured backup directory
262	/// * `db_file_path` — filesystem path of the primary SQLite database file
263	pub fn apply_pending_restore(backup_dir: &Path, db_file_path: &Path) -> Result<bool, String> {
264	    let marker = backup_dir.join(RESTORE_MARKER);
265	    if !marker.exists() {
266	        return Ok(false);
267	    }
268	
269	    let content =
270	        std::fs::read_to_string(&marker).map_err(|e| format!("Cannot read restore marker: {e}"))?;
271	    let backup_path = PathBuf::from(content.trim());
272	
273	    if !backup_path.exists() {
274	        std::fs::remove_file(&marker).ok();
275	        return Err(format!(
276	            "Staged restore file '{}' no longer exists — marker removed",
277	            backup_path.display()
278	        ));
279	    }
280	
281	    // Validate before overwriting.
282	    validate_sqlite_file(&backup_path)
283	        .map_err(|e| format!("Staged restore file is corrupt: {e}"))?;
284	
285	    // Ensure the target directory exists.
286	    if let Some(parent) = db_file_path.parent() {
287	        std::fs::create_dir_all(parent).map_err(|e| format!("Cannot create db directory: {e}"))?;
288	    }
289	
290	    std::fs::copy(&backup_path, db_file_path).map_err(|e| format!("Restore copy failed: {e}"))?;
291	
292	    std::fs::remove_file(&marker)
293	        .map_err(|e| format!("Cannot remove restore marker after apply: {e}"))?;
294	
295	    tracing::info!(
296	        backup = %backup_path.display(),
297	        target = %db_file_path.display(),
298	        "backup.restore_applied"
299	    );
300	
301	    Ok(true)
302	}
303	
304	/// Extract the filesystem path from a SQLite `DATABASE_URL`.
305	///
306	/// Handles the common formats used by sqlx/sea-orm:
307	/// - `sqlite:///absolute/path.db`  →  `/absolute/path.db`
308	/// - `sqlite://./relative.db`       →  `./relative.db`
309	/// - `sqlite://relative.db`         →  `relative.db`
310	pub fn db_path_from_url(url: &str) -> Option<PathBuf> {
311	    let stripped = url.strip_prefix("sqlite://")?;
312	    // Triple-slash absolute path: strip one leading slash.
313	    let path_str = if let Some(s) = stripped.strip_prefix('/') {
314	        format!("/{s}")
315	    } else {
316	        stripped.to_owned()
317	    };
318	    Some(PathBuf::from(path_str))
319	}
