65	/// Convert Rocket's default HTML 422 response into a structured JSON body.
66	/// Triggered when JSON deserialization of the request body fails (e.g. missing
67	/// required field) before the route handler is even called.
68	#[catch(422)]
69	fn catch_unprocessable(req: &rocket::Request<'_>) -> Json<errors::ErrorBody> {
70	    let cid = req
71	        .local_cache(|| middleware::correlation::CorrelationId(String::new()))
72	        .0
73	        .clone();
74	    Json(errors::ErrorBody {
75	        code: "UNPROCESSABLE_ENTITY",
76	        message: "The request body could not be parsed or contains invalid values.".to_string(),
77	        correlation_id: if cid.is_empty() { None } else { Some(cid) },
78	    })
79	}
